VALUES
('bookkeeper-moex-01237', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '乙公司於X3年10月15日簽發一張90天期，5%，面額$300,000的票據一張，藉此票據以清償即將到期 的帳款。若一年以360天計算，此票據之到期日應為：', '["X3年12月31日", "X4年1月13日", "X4年1月15日", "X4年1月31日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01238', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '大甲公司過去向小乙公司購入一項工具專利權，$1,000,000，目前該專利權帳面價值為$600,000。然而， 公司本年度發現中丙公司仿製公司專利，經訴訟後獲得勝訴，訴訟費用合計$200,000。重新評估該專利權 可使用兩年預計產生$450,000之淨現金流量折現值，另外經估價該專利權之淨公允價值為$400,000。請問 下列敘述何者正確？', '["維護專利權勝訴的費用$200,000，應列為當年度費用", "專利權餘額應採用現金流量折現值加本年度專利權訴訟維護費用$470,000列為專利權成本", "專利權應採用帳面價值$600,000攤銷", "本年度專利權應用可收回現值價值與公允價值較低者列帳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01239', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', 'X2年12月31日，乙公司已發行之普通股10,000股，每股面額$10，同時，累積與完全參加特別股2,000 股，每股面額$25，股利率5%。X3年度乙公司宣告並發放現金股利$15,000，X4年並未宣告現金股利。 請問當乙公司採用曆年制會計年度，X4年12月31日「應付現金股利」之餘額為：', '["$0", "$2,500", "$5,000", "$15,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01240', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法之規定，下列關於納稅義務人之敘述，何者正確？ 共有財產設有管理人者，由使用人負納稅義務 公同共有財產未設管理人者，共有人各按其應有部分負納稅義務 分別共有財產未設管理人者，以全體共有人為納稅義務人 營利事業因合併而消滅時，其在合併前之應納稅捐，應由合併後存續或另立之營利事業負繳納之義務', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01241', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法之規定，營利事業因故被補徵稅款，繳納期限至民國104年7月14日（星期二）截止， 因不服欲申請復查，最遲應於何日前提出？ 104年8月13日  104年8月12日  104年8月14日  104年9月13日', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01242', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法第48條之1的規定，納稅義務人在未經檢舉、調查前，自動向稅捐稽徵機關補報並補繳 所漏稅款者，下列敘述何者正確？ 加計利息免罰  加計利息減半處罰  免加計利息免罰  免加計利息減半處罰', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01243', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '張無忌104年度之房屋稅繳款書，經臺北市稅捐稽徵處中正分處於104年4月20日送達。該房屋稅核定應 納稅額為10萬元，繳納期間為104年5月1日至5月31日（星期日），若張無忌於104年6月3日繳納 該稅款，依現行稅捐稽徵法規定，應加徵滯納金若干？ 0元  1千元  2千元  1萬5千元', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01244', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法之規定，下列敘述何者錯誤？ 申請獲准延期或分期繳納稅款之期間不超過3年 納稅義務人因自行計算錯誤而溢繳之稅款，得於5年內申請退還 稅捐機關對復查之申請案，應於2個月內做成復查決定書 受理稅捐案件訴願之機關，應於6個月內做成訴願決定書', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01245', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '根據現行稅捐稽徵法的規定，依法應由納稅義務人申報繳納之稅捐，已在規定期限內申報者，其核課期間之 起算日為： 申報日  申報期間屆滿日  申報期間屆滿之翌日  所屬徵期屆滿之翌日', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01246', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法之規定，納稅義務人有欠繳應納稅捐者，稅捐稽徵機關得採取下列那些租稅保全措施？', '["限制其註銷或減資登記", "給予停業處分", "禁止財產移轉或設定他項權利", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01247', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法之規定，有關稅捐得提前徵收之情況，下列敘述何者錯誤？ 納稅義務人顯有隱匿財產，逃避稅捐執行之跡象者 納稅義務人故意以詐欺或不正當方法逃漏稅捐者 納稅義務人於稅捐法定徵收日前申請離境者 納稅義務人受破產宣告前，應徵之稅捐尚未開徵者', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01248', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行營利事業所得稅查核準則之規定，營利事業取得小規模營利事業出具之普通收據，其全年累計金額以 不超過當年度經稽徵機關核定之製造費用及營業費用總額之多少百分比為限？ 1%  3%  5%  10%', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01249', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行營利事業所得稅查核準則之規定，職工退休金準備、職工退休基金、勞工退休準備金，三者以費用列 支之限額依序為當年度已付薪資總額之多少百分比？ 2%、5%、10%  4%、8%、15%  4%、8%、20%  5%、10%、15%', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01250', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行營利事業所得稅查核準則及相關規定，營利事業透過財團法人私立學校興學基金會，指定對私立○○ 大學之捐款，得列為費用者，以不超過所得額之多少百分比為限？ 10%  25%  50%  100%', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01251', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '良友公司以公司名義為受益人，為員工投保團體人壽保險，依現行營利事業所得稅查核準則之規定，由該公 司負擔部分，每人每月保險費合計最多在新臺幣多少元以內，免視為被保險員工之薪資所得？ 1千8百元  2千元  5千元  1萬元', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
